import React, { useState, useCallback } from 'react';
import Header from './components/Header';
import HeroSlider from './components/HeroSlider';
import ActionsBar from './components/ActionsBar';
import FeaturesServices from './components/FeaturesServices';
import AboutUs from './components/AboutUs';
import MedicalNetwork from './components/MedicalNetwork';
import Discounts from './components/Discounts';
import NearbyServices from './components/NearbyServices';
import FAQ from './components/FAQ';
import Footer from './components/Footer';
import ErrorBoundary from './components/ErrorBoundary';
import Toast, { ToastType } from './components/Toast';

const App: React.FC = () => {
  const [notification, setNotification] = useState<{ message: string; type: ToastType } | null>(null);

  const notify = useCallback((message: string, type: ToastType = 'info') => {
    setNotification({ message, type });
  }, []);

  return (
    <div className="min-h-screen flex flex-col bg-[#f8fcfc]">
      <Header />
      <main className="flex-grow">
        <ErrorBoundary>
          <HeroSlider />
        </ErrorBoundary>

        <div className="relative z-10 -mt-10 md:-mt-16 container mx-auto px-4">
          <ErrorBoundary>
            <ActionsBar />
          </ErrorBoundary>
        </div>

        <ErrorBoundary>
          <FeaturesServices />
        </ErrorBoundary>

        <ErrorBoundary>
          <AboutUs />
        </ErrorBoundary>

        <ErrorBoundary>
          <MedicalNetwork />
        </ErrorBoundary>

        <ErrorBoundary>
          <Discounts notify={notify} />
        </ErrorBoundary>

        <ErrorBoundary>
          <NearbyServices notify={notify} />
        </ErrorBoundary>

        <ErrorBoundary>
          <FAQ />
        </ErrorBoundary>
      </main>
      <Footer />

      {notification && (
        <Toast
          message={notification.message}
          type={notification.type}
          onClose={() => setNotification(null)}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { ChevronRight, ChevronLeft, Play, Pause, Zap } from 'lucide-react';

