import React, { useState, useEffect } from 'react';
import { MapPin, Navigation, Hospital, Loader2, AlertCircle, Activity, Globe, Shield, Zap } from 'lucide-react';
import { ToastType } from './Toast';

interface NearbyServicesProps {
  notify?: (message: string, type: ToastType) => void;
}

const NearbyServices: React.FC<NearbyServicesProps> = ({ notify }) => {
  const [loading, setLoading] = useState(false);
  const [location, setLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [stats, setStats] = useState({ providers: 142, ambulances: 18 });

  useEffect(() => {
    const interval = setInterval(() => {
      setStats(prev => ({
        providers: prev.providers + (Math.random() > 0.5 ? 1 : -1),
        ambulances: Math.max(5, prev.ambulances + (Math.random() > 0.7 ? 1 : -1))
      }));
    }, 5000);
    return () => clearInterval(interval);
  }, []);

  const handleGetLocation = () => {
    setLoading(true);
    setError(null);
    if (!navigator.geolocation) {
      setError('متصفحك لا يدعم تحديد الموقع.');
      setLoading(false);
      return;
    }
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        setLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude });
        setLoading(false);
        notify?.('تم تحديد موقعك بنجاح!', 'success');
      },
      () => {
        setError('تعذر تحديد موقعك. يرجى تفعيل الإذن.');
        setLoading(false);
      }
    );
  };

  const mapUrl = location 
    ? `https://maps.google.com/maps?q=${location.lat},${location.lng}&t=&z=15&ie=UTF8&iwloc=&output=embed`
    : `https://maps.google.com/maps?q=Jeddah,KSA&t=&z=13&ie=UTF8&iwloc=&output=embed`;

  return (
    <section className="py-24 bg-[#002b2b] text-white relative overflow-hidden">
      <div className="container mx-auto px-4 relative z-10">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-16 items-center">
          <div className="space-y-8">
            <div className="inline-flex items-center gap-2 px-4 py-2 bg-teal-500/10 border border-teal-500/20 rounded-full text-teal-400 text-sm font-black">
              <span className="relative flex h-2 w-2">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-teal-400 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-2 w-2 bg-teal-500"></span>
              </span>
              بث حي - خريطة أمان الذكية
            </div>

            <h2 className="text-4xl md:text-6xl font-black leading-tight">خدماتنا <br /><span className="text-teal-400">تحيط بك أينما كنت</span></h2>
            <p className="text-lg text-teal-100/70 font-bold leading-relaxed max-w-lg">
              عبر تقنية أمان الذكية، نوفر لك خريطة تفاعلية تظهر أقرب مقدمي الرعاية المتاحين فوراً في محيطك الجغرافي.
            </p>

            <div className="grid grid-cols-2 gap-4">
              <div className="bg-white/5 border border-white/10 p-6 rounded-3xl">
                <Hospital className="text-teal-400 mb-2" size={24} />
                <div className="text-3xl font-black">{stats.providers}</div>
                <div className="text-xs text-teal-400/60 font-bold">مركز طبي متاح</div>
              </div>
              <div className="bg-white/5 border border-white/10 p-6 rounded-3xl">
                <Activity className="text-emerald-400 mb-2" size={24} />
                <div className="text-3xl font-black">{stats.ambulances}</div>
                <div className="text-xs text-emerald-400/60 font-bold">وحدة طوارئ نشطة</div>
              </div>
            </div>

            <div className="flex flex-col sm:flex-row gap-4">
              <button 
                onClick={handleGetLocation}
                disabled={loading}
                className="px-8 py-4 bg-teal-600 text-white rounded-2xl font-black flex items-center justify-center gap-3 hover:bg-teal-500 transition-all disabled:opacity-50 shadow-xl shadow-teal-900/40"
              >
                {loading ? <Loader2 className="animate-spin" /> : <Navigation size={20} />}
                تحديد أقرب مركز طبي
              </button>
              <button className="px-8 py-4 bg-white/5 border border-white/10 rounded-2xl font-black flex items-center justify-center gap-3 hover:bg-white/10 transition-all">
                <Globe size={20} /> خريطة الشبكة الكاملة
              </button>
            </div>
          </div>

          <div className="relative">
            <div className="absolute -top-10 -right-10 w-40 h-40 bg-teal-500 rounded-full blur-[100px] opacity-20"></div>
            <div className="relative w-full aspect-square bg-[#001a1a] rounded-[3.5rem] overflow-hidden border-8 border-white/5 shadow-2xl group">
              <iframe
                title="Map"
                width="100%"
                height="100%"
                src={mapUrl}
                className={`transition-all duration-1000 ${loading ? 'opacity-30 blur-sm' : 'opacity-80 group-hover:opacity-100'}`}
                style={{ filter: 'invert(90%) hue-rotate(150deg) brightness(0.9) contrast(1.2)' }}
              />

              <div className="absolute inset-0 pointer-events-none p-6 flex flex-col justify-between">
                <div className="bg-black/40 backdrop-blur-md border border-white/10 px-4 py-3 rounded-2xl w-fit flex items-center gap-3">
                  <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
                  <div className="text-[10px] font-black tracking-wider text-teal-50">تحديث فوري للنطاق الجغرافي</div>
                </div>

                <div className="bg-white/10 backdrop-blur-xl border border-white/10 p-4 rounded-2xl flex items-center gap-4 animate-in slide-in-from-right-10">
                  <div className="w-12 h-12 bg-teal-600 rounded-xl flex items-center justify-center shadow-lg">
                    <Shield className="text-white" size={24} />
                  </div>
                  <div>
                    <h4 className="font-black text-sm">أمان لايف نشط</h4>
                    <p className="text-[10px] text-teal-100/60 font-bold">أنت الآن في منطقة تغطية طبية آمنة</p>
                  </div>
                </div>
              </div>

              {loading && (
                <div className="absolute inset-0 bg-[#002b2b]/60 backdrop-blur-sm flex flex-col items-center justify-center">
                  <Loader2 className="w-12 h-12 text-teal-400 animate-spin" />
                  <p className="mt-4 font-black tracking-widest text-teal-200">جاري مسح المنطقة...</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default NearbyServices;

