  }
];

const FALLBACK_IMAGE = "https://images.unsplash.com/photo-1516549655169-df83a0774514?auto=format&fit=crop&q=80&w=1920";

const HeroSlider: React.FC = () => {
  const [current, setCurrent] = useState(0);
  const [isPaused, setIsPaused] = useState(false);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const thumbRefs = useRef<(HTMLButtonElement | null)[]>([]);

  const startTimer = () => {
    if (timerRef.current) clearInterval(timerRef.current);
    timerRef.current = setInterval(() => {
      if (!isPaused) {
        setCurrent((prev) => (prev === slides.length - 1 ? 0 : prev + 1));
      }
    }, 6000);
  };

  useEffect(() => {
    startTimer();
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [isPaused]);

  // Handle auto-scrolling of thumbnails without affecting window scroll
  useEffect(() => {
    const container = scrollContainerRef.current;
    const activeThumb = thumbRefs.current[current];

    if (container && activeThumb) {
      const containerWidth = container.offsetWidth;
      const thumbLeft = activeThumb.offsetLeft;
      const thumbWidth = activeThumb.offsetWidth;

      // Calculate position to center the active thumb in the container
      const newScrollLeft = thumbLeft + (thumbWidth / 2) - (containerWidth / 2);

      container.scrollTo({
        left: newScrollLeft,
        behavior: 'smooth'
      });
    }
  }, [current]);

  const next = () => {
    setCurrent((prev) => (prev === slides.length - 1 ? 0 : prev + 1));
    startTimer();
  };

  const prev = () => {
    setCurrent((prev) => (prev === 0 ? slides.length - 1 : prev - 1));
    startTimer();
  };

  const handleImageError = (e: React.SyntheticEvent<HTMLImageElement, Event>) => {
    e.currentTarget.src = FALLBACK_IMAGE;
  };

  return (
    <section className="relative h-[600px] sm:h-[700px] lg:h-[800px] w-full overflow-hidden bg-[#001f1f] group">
      {/* Main Slides */}
      <div className="relative w-full h-full">
        {slides.map((slide, index) => (
          <div
            key={index}
            className={`absolute inset-0 transition-all duration-1000 ease-in-out ${
              index === current ? 'opacity-100 z-10 translate-x-0 scale-100' : 'opacity-0 z-0 translate-x-12 scale-105'
            }`}
          >
            <img
              src={slide.image}
              alt={slide.title}
              onError={handleImageError}
              className={`w-full h-full object-cover transition-transform duration-[15000ms] linear ${index === current ? 'scale-110' : 'scale-100'}`}
            />
            <div className={`absolute inset-0 bg-gradient-to-r ${slide.color} flex items-center`}>
              <div className="container mx-auto px-6 md:px-12 text-white">
                <div className={`max-w-3xl transform transition-all duration-1000 delay-300 ${index === current ? 'translate-y-0 opacity-100' : 'translate-y-20 opacity-0'}`}>
                  <div className="flex items-center gap-3 mb-6">
                    <span className="inline-flex items-center gap-2 px-4 py-1.5 bg-white/10 backdrop-blur-md rounded-full text-xs font-black border border-white/20 animate-pulse">
                      <Zap size={14} className="text-yellow-400" />
                      عضوية أمان إيفر الحصرية
                    </span>
                  </div>

                  <h1 className="text-4xl sm:text-6xl lg:text-7xl font-black mb-8 leading-tight drop-shadow-xl">
                    {slide.title}
                  </h1>

                  <p className="text-lg sm:text-xl mb-12 text-teal-50/90 font-bold leading-relaxed max-w-2xl">
                    {slide.description}
                  </p>

                  <div className="flex flex-col sm:flex-row gap-5">
                    <button className="px-10 py-4 bg-[#006666] text-white rounded-2xl font-black text-lg hover:bg-[#004d4d] transition-all shadow-xl hover:scale-105 active:scale-95 flex items-center justify-center gap-3 group/btn">
                      {slide.cta}
                      <ChevronLeft className="rtl-flip transition-transform group-hover/btn:-translate-x-1" />
                    </button>
                    <button className="px-10 py-4 bg-white/10 backdrop-blur-md border border-white/30 text-white rounded-2xl font-black text-lg hover:bg-white/20 transition-all active:scale-95">
                      اكتشف الشبكة
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Navigation & Thumbs */}
      <div className="absolute bottom-10 left-0 right-0 z-30 container mx-auto px-4">
        <div className="flex flex-col lg:flex-row items-center justify-between gap-6 bg-black/30 backdrop-blur-xl border border-white/10 p-4 rounded-[2.5rem] shadow-2xl">
          {/* Thumbnails Container */}
          <div 
            ref={scrollContainerRef}
            className="flex-grow flex items-center gap-4 overflow-x-auto no-scrollbar scroll-smooth w-full lg:w-auto"
          >
            {slides.map((slide, idx) => (
              <button
                key={idx}
                ref={el => thumbRefs.current[idx] = el}
                onClick={() => { setCurrent(idx); startTimer(); }}
                className={`relative shrink-0 w-28 h-16 rounded-xl overflow-hidden border-2 transition-all duration-500 group/thumb ${
                  idx === current 
                    ? 'border-[#006666] scale-105 z-20 shadow-lg ring-2 ring-[#006666]/30' 
                    : 'border-white/10 opacity-70 hover:opacity-100 hover:border-white/30'
                }`}
              >
                <img src={slide.image} className="w-full h-full object-cover transition-transform duration-700 group-hover/thumb:scale-110" alt="" onError={handleImageError} />

                {/* Active Progress Bar */}
                {idx === current && (
                   <div className="absolute bottom-0 left-0 right-0 h-1 bg-[#006666] origin-left animate-[progress_6s_linear]" />
                )}

                {/* Inactive Overlay */}
                <div className={`absolute inset-0 bg-black/40 transition-opacity duration-300 ${idx === current ? 'opacity-0' : 'opacity-100 group-hover/thumb:opacity-0'}`}></div>
              </button>
            ))}
          </div>

          <div className="flex items-center gap-4 shrink-0 px-4">
            <button 
              onClick={() => setIsPaused(!isPaused)}
              className="w-12 h-12 rounded-full bg-white/10 hover:bg-white/20 text-white flex items-center justify-center transition-all border border-white/10 active:scale-95"
            >
              {isPaused ? <Play size={20} fill="currentColor" /> : <Pause size={20} fill="currentColor" />}
            </button>
            <div className="flex gap-2">
              <button onClick={prev} className="w-12 h-12 rounded-xl bg-white text-[#006666] hover:bg-teal-50 flex items-center justify-center shadow-lg transition-transform hover:scale-105 active:scale-95">
                <ChevronRight className="w-6 h-6" />
              </button>
              <button onClick={next} className="w-12 h-12 rounded-xl bg-white text-[#006666] hover:bg-teal-50 flex items-center justify-center shadow-lg transition-transform hover:scale-105 active:scale-95">
                <ChevronLeft className="w-6 h-6" />
              </button>
            </div>
          </div>
        </div>
      </div>

      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
        @keyframes progress { from { transform: scaleX(0); } to { transform: scaleX(1); } }
      `}</style>
    </section>
  );
};

export default HeroSlider;

