                 placeholder="بحث عن وحدة (إسعاف، مستشفى، طبيب)..."
                 className="w-full bg-white/5 backdrop-blur-xl border-2 border-white/10 focus:border-teal-500/50 outline-none pr-14 pl-12 py-5 rounded-[2rem] font-black text-white placeholder:text-white/30 transition-all shadow-2xl"
                 value={searchQuery}
                 onChange={(e) => setSearchQuery(e.target.value)}
               />
               <div className="absolute inset-y-0 left-6 flex items-center">
                 {searchQuery ? (
                   <button onClick={() => setSearchQuery('')} className="p-2 hover:bg-white/10 rounded-full text-white/50 hover:text-white transition-all">
                     <X size={18} />
                   </button>
                 ) : (
                   <div className="flex items-center gap-2 px-3 py-1 bg-teal-500/20 border border-teal-500/30 rounded-full">
                      <span className="text-[10px] font-black text-teal-400 uppercase tracking-widest">Tracking {filteredAssets.length} Units</span>
                   </div>
                 )}
               </div>
            </div>

            <div className="relative group">
              <div className="absolute -top-4 -right-4 w-12 h-12 border-t-4 border-r-4 border-teal-500/40 rounded-tr-3xl"></div>
              <div className="absolute -bottom-4 -left-4 w-12 h-12 border-b-4 border-l-4 border-teal-500/40 rounded-bl-3xl"></div>

              <div className="relative w-full aspect-[16/10] bg-[#001a1a] rounded-[3.5rem] overflow-hidden border-8 border-white/5 shadow-2xl">
                <iframe
                  title="Tactical Map"
                  width="100%"
                  height="100%"
                  src={mapUrl}
                  className={`transition-all duration-1000 grayscale-[0.8] contrast-[1.2] brightness-[0.7] ${loading ? 'opacity-30 blur-md' : 'opacity-100'}`}
                  style={{ filter: 'invert(90%) hue-rotate(150deg) brightness(0.8) contrast(1.3)' }}
                />

                <div className="absolute inset-0 pointer-events-none overflow-hidden">
                  <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[200%] h-[200%] origin-center animate-[spin_10s_linear_infinite] opacity-20">
                     <div className="w-1/2 h-1/2 bg-gradient-to-tr from-teal-500/40 to-transparent rounded-tr-full"></div>
                  </div>

                  <div className="absolute inset-0 opacity-10" style={{ backgroundImage: 'radial-gradient(circle, #2dd4bf 1px, transparent 0)', backgroundSize: '40px 40px' }}></div>

                  {/* Filtered Dynamic Markers */}
                  {filteredAssets.map(asset => (
                    <AssetMarker 
                      key={asset.id}
                      top={asset.top} 
                      left={asset.left} 
                      label={asset.label} 
                      type={asset.type} 
                      active={asset.active} 
                      delay={asset.delay} 
                    />
                  ))}

                  {filteredAssets.length === 0 && (
                    <div className="absolute inset-0 flex items-center justify-center bg-black/40 backdrop-blur-sm">
                       <div className="text-center p-8 bg-black/60 rounded-3xl border border-white/10">
                          <Search size={48} className="mx-auto text-teal-500 mb-4 opacity-50" />
                          <h4 className="text-xl font-black mb-1">لا توجد نتائج</h4>
                          <p className="text-sm text-white/50 font-bold">لم نتمكن من العثور على الوحدة المطلوبة</p>
                       </div>
                    </div>
                  )}

                  <div className="absolute top-8 left-8 p-4 bg-black/40 backdrop-blur-xl border border-white/10 rounded-2xl">
                    <div className="flex items-center gap-3 mb-2">
                       <Zap size={14} className="text-teal-400" />
                       <span className="text-[10px] font-black tracking-tighter">نظام الكشف النشط</span>
                    </div>
                    <div className="font-mono text-[9px] text-teal-200 opacity-60">
                      LAT: {location?.lat.toFixed(4) || '21.5433'}<br />
                      LNG: {location?.lng.toFixed(4) || '39.1728'}<br />
                      QUERY: {searchQuery || 'NONE'}
                    </div>
                  </div>
                </div>

                {loading && (
                  <div className="absolute inset-0 bg-[#002b2b]/80 backdrop-blur-md flex flex-col items-center justify-center p-8 text-center">
                    <div className="relative mb-8">
                       <div className="w-24 h-24 border-4 border-teal-500/20 border-t-teal-500 rounded-full animate-spin"></div>
                       <div className="absolute inset-0 flex items-center justify-center text-teal-400">
                         <Navigation size={32} />
                       </div>
                    </div>
                    <h3 className="text-2xl font-black mb-2 text-white">بروتوكول تحديد الموقع</h3>
                    <p className="text-teal-400 font-bold mb-6">{scanLabels[scanStep]}</p>
                    <div className="w-64 h-2 bg-white/10 rounded-full overflow-hidden">
                       <div 
                         className="h-full bg-teal-500 transition-all duration-500 ease-out" 
                         style={{ width: `${(scanStep / 3) * 100}%` }}
                       ></div>
                    </div>
                  </div>
                )}
              </div>
            </div>

            <div className="mt-12 flex flex-col sm:flex-row gap-6 items-center justify-between">
              <div className="flex items-center gap-6">
                 <div className="flex items-center gap-2">
                    <span className="w-3 h-3 bg-teal-500 rounded-full"></span>
                    <span className="text-xs font-bold text-white/60">مركز طبي</span>
                 </div>
                 <div className="flex items-center gap-2">
                    <span className="w-3 h-3 bg-amber-500 rounded-full"></span>
                    <span className="text-xs font-bold text-white/60">إسعاف متحرك</span>
                 </div>
                 <div className="flex items-center gap-2">
                    <span className="w-3 h-3 bg-blue-500 rounded-full"></span>
                    <span className="text-xs font-bold text-white/60">طبيب استشاري</span>
                 </div>
              </div>

              <div className="flex gap-4">
                <button 
                  onClick={handleGetLocation}
                  disabled={loading}
                  className="px-10 py-5 bg-teal-600 text-white rounded-3xl font-black flex items-center gap-3 hover:bg-teal-500 transition-all disabled:opacity-50 shadow-2xl shadow-teal-900/40"
                >
                  {loading ? <Loader2 className="animate-spin" /> : <Navigation size={22} />}
                  بدء المسح الشامل
                </button>
                <button className="p-5 bg-white/5 border border-white/10 rounded-3xl hover:bg-white/10 transition-all">
                  <Globe size={24} />
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

const AssetMarker = ({ top, left, label, type, active, delay = 0 }: any) => {
  const color = type === 'ambulance' ? 'bg-amber-500' : type === 'doctor' ? 'bg-blue-500' : 'bg-teal-500';

  return (
    <div 
      className="absolute flex flex-col items-center transition-all duration-[2000ms] ease-linear"
      style={{ top, left }}
    >
      <div className={`relative group/marker cursor-crosshair animate-in fade-in zoom-in duration-500`} style={{ animationDelay: `${delay}ms` }}>
        <div className={`absolute -inset-4 ${color} rounded-full opacity-20 animate-ping`}></div>
        <div className={`w-3 h-3 ${color} rounded-full shadow-[0_0_15px_rgba(255,255,255,0.5)] border-2 border-white`}></div>
        <div className="absolute top-5 left-1/2 -translate-x-1/2 bg-black/80 backdrop-blur-md border border-white/10 px-2 py-1 rounded text-[8px] font-black tracking-widest text-white whitespace-nowrap opacity-60 group-hover/marker:opacity-100 transition-opacity">
          {label} {active && '• MOVING'}
        </div>
      </div>
    </div>
  );
};

