const HeroSlider: React.FC = () => {
  const [current, setCurrent] = useState(0);
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const thumbRefs = useRef<(HTMLButtonElement | null)[]>([]);

  // Smart Auto-slide logic: Resets timer on manual interaction
  useEffect(() => {
    const timer = setTimeout(() => {
      setCurrent((prev) => (prev === slides.length - 1 ? 0 : prev + 1));
    }, 6000);

    return () => clearTimeout(timer);
  }, [current]);

  // Handle auto-scrolling of thumbnails
  useEffect(() => {
    const container = scrollContainerRef.current;
    // Safely get the active thumbnail ref
    const activeThumb = thumbRefs.current[current];

    if (container && activeThumb) {
      const containerWidth = container.offsetWidth;
      const thumbLeft = activeThumb.offsetLeft;
      const thumbWidth = activeThumb.offsetWidth;

      const newScrollLeft = thumbLeft + (thumbWidth / 2) - (containerWidth / 2);

      // Using requestAnimationFrame to ensure smooth visual update without blocking the main thread
      // This prevents the "page trying to scroll" feeling.
      requestAnimationFrame(() => {
        container.scrollTo({
          left: newScrollLeft,
          behavior: 'smooth'
        });
      });
    }
  }, [current]);

  const next = () => {
    setCurrent((prev) => (prev === slides.length - 1 ? 0 : prev + 1));
  };

  const prev = () => {
    setCurrent((prev) => (prev === 0 ? slides.length - 1 : prev - 1));
  };

  const handleImageError = (e: React.SyntheticEvent<HTMLImageElement, Event>) => {
    e.currentTarget.src = FALLBACK_IMAGE;
  };

  return (
    <section className="relative h-[600px] sm:h-[700px] lg:h-[800px] w-full overflow-hidden bg-[#001f1f] group" dir="ltr">
      {/* 
        Note: dir="ltr" is applied to the slider container to ensure the 
        animations work consistently without jittering in RTL mode.
        The content inside is correctly flipped back to RTL.
      */}

      {/* Main Slides */}
      <div className="relative w-full h-full">
        {slides.map((slide, index) => (
          <div
            key={index}
            className={`absolute inset-0 transition-opacity duration-1000 ease-in-out ${
              index === current ? 'opacity-100 z-10' : 'opacity-0 z-0'
            }`}
          >
            {/* Background Image with optimized rendering */}
            <div className="absolute inset-0 overflow-hidden">
               <img
                src={slide.image}
                alt={slide.title}
                onError={handleImageError}
                className={`w-full h-full object-cover will-change-transform transition-transform duration-[10000ms] linear ${
                  index === current ? 'scale-110' : 'scale-100'
                }`}
              />
            </div>

            {/* Content Overlay - Forced RTL for text correctness */}
            <div className={`absolute inset-0 bg-gradient-to-r ${slide.color} flex items-center`} dir="rtl">
              <div className="container mx-auto px-6 md:px-12 text-white">
                <div className={`max-w-3xl transition-all duration-700 delay-300 transform ${
                  index === current ? 'translate-y-0 opacity-100' : 'translate-y-10 opacity-0'
                }`}>
                  <div className="flex items-center gap-3 mb-6">
                    <span className="inline-flex items-center gap-2 px-4 py-1.5 bg-white/10 backdrop-blur-md rounded-full text-xs font-black border border-white/20 animate-pulse">
                      <Zap size={14} className="text-yellow-400" />
                      عضوية أمان إيفر الحصرية
                    </span>
                  </div>

                  <h1 className="text-4xl sm:text-6xl lg:text-7xl font-black mb-8 leading-tight drop-shadow-xl">
                    {slide.title}
                  </h1>

                  <p className="text-lg sm:text-xl mb-12 text-teal-50/90 font-bold leading-relaxed max-w-2xl">
                    {slide.description}
                  </p>

                  <div className="flex flex-col sm:flex-row gap-5">
                    <button className="px-10 py-4 bg-[#006666] text-white rounded-2xl font-black text-lg hover:bg-[#004d4d] transition-all shadow-xl hover:scale-105 active:scale-95 flex items-center justify-center gap-3 group/btn">
                      {slide.cta}
                      <ChevronLeft className="rtl-flip transition-transform group-hover/btn:-translate-x-1" />
                    </button>
                    <button className="px-10 py-4 bg-white/10 backdrop-blur-md border border-white/30 text-white rounded-2xl font-black text-lg hover:bg-white/20 transition-all active:scale-95">
                      اكتشف الشبكة
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Navigation & Thumbs */}
      <div className="absolute bottom-10 left-0 right-0 z-30 container mx-auto px-4" dir="rtl">
        <div className="flex flex-col lg:flex-row items-center justify-between gap-6 bg-black/30 backdrop-blur-xl border border-white/10 p-4 rounded-[2.5rem] shadow-2xl">
          {/* Thumbnails Container */}
          <div 
            ref={scrollContainerRef}
            className="flex-grow flex items-center gap-4 overflow-x-auto no-scrollbar scroll-smooth w-full lg:w-auto"
          >
            {slides.map((slide, idx) => (
              <button
                key={idx}
                ref={el => { thumbRefs.current[idx] = el; }}
