                }`}
              >
                <img 
                  src={slide.image} 
                  className="w-full h-full object-cover" 
                  alt="" 
                  onError={handleImageError} 
                />

                {/* Active Progress Bar */}
                {idx === current && (
                   <div className="absolute bottom-0 left-0 right-0 h-1 bg-[#006666] origin-left animate-[progress_6s_linear]" />
